(718, 79, '1', 50, '1', '<p>&nbsp;<span style=\"color: rgba(41, 41, 41, 0.9); font-family: Poppins, sans-serif; font-size: 18px;\">Which option is used to place data taken in pen drive or CD to Appropriate place in Tally?</span></p>\r\n<p style=\"box-sizing: inherit; margin: 0px 0px 1.333em; word-break: break-word; color: rgba(41, 41, 41, 0.9); font-family: Poppins, sans-serif; font-size: 18px;\"><span lang=\"HI\" style=\"box-sizing: inherit; font-family: &quot;Arial Unicode MS&quot;, &quot;sans-serif&quot;; line-height: 20.7px;\">à¤ªà¥à¤¨ à¤¡à¥à¤°à¤¾à¤à¤µ à¤¯à¤¾ à¤¸à¥à¤¡à¥ à¤®à¥à¤ à¤²à¤¿à¤ à¤à¤ à¤¡à¥à¤à¤¾ à¤à¥ à¤à¥à¤²à¥ à¤®à¥à¤ à¤à¤ªà¤¯à¥à¤à¥à¤¤ à¤¸à¥à¤¥à¤¾à¤¨ à¤ªà¤° à¤°à¤à¤¨à¥ à¤à¥ à¤²à¤¿à¤ à¤à¤¿à¤¸ à¤µà¤¿à¤à¤²à¥à¤ª à¤à¤¾ à¤à¤ªà¤¯à¥à¤ à¤à¤¿à¤¯à¤¾ à¤à¤¾à¤¤à¤¾ à¤¹à¥</span>?</p>', '<p>&nbsp;<span style=\"font-family: Poppins, sans-serif; font-size: 18px;\">Split company Data</span></p>', '<p>&nbsp;<span style=\"font-family: Poppins, sans-serif; font-size: 18px;\">Restore</span></p>', '<p>&nbsp;<span style=\"color: rgba(41, 41, 41, 0.9); font-family: Poppins, sans-serif; font-size: 18px;\">Backup</span></p>', '<p>&nbsp;<span style=\"color: rgba(41, 41, 41, 0.9); font-family: Poppins, sans-serif; font-size: 18px;\">None of these</span></p>', '', '', '', '', '', '', '', '', '', 2, '', 1, '149', 149, 0, '', '1', 0),
(719, 79, '1', 50, '1', '<p>&nbsp;<span style=\"color: rgba(41, 41, 41, 0.9); font-family: Poppins, sans-serif; font-size: 18px;\">Which of the following is not a transaction?</span></p>\r\n<p style=\"box-sizing: inherit; margin: 0px 0px 1.333em; word-break: break-word; color: rgba(41, 41, 41, 0.9); font-family: Poppins, sans-serif; font-size: 18px;\"><span lang=\"HI\" style=\"box-sizing: inherit; font-family: &quot;Arial Unicode MS&quot;, &quot;sans-serif&quot;; line-height: 20.7px;\">à¤¨à¤¿à¤®à¥à¤¨à¤²à¤¿à¤à¤¿à¤¤ à¤®à¥à¤ à¤¸à¥ à¤à¥à¤¨ à¤¸à¤¾ à¤²à¥à¤¨à¤¦à¥à¤¨ à¤¨à¤¹à¥à¤ à¤¹à¥</span>?</p>', '<p>&nbsp;<span style=\"font-family: Poppins, sans-serif; font-size: 18px;\">Land is purchased for Rs 10 lakhs</span></p>', '<p>&nbsp;<span style=\"font-family: Poppins, sans-serif; font-size: 18px;\">Salaries paid for the amount of May 2009</span></p>', '<p>&nbsp;<span style=\"color: rgba(41, 41, 41, 0.9); font-family: Poppins, sans-serif; font-size: 18px;\">Goods are purchased on cash basis for Rs 1000</span></p>', '<p>&nbsp;<span style=\"font-family: Poppins, sans-serif; font-size: 18px;\">An employee is dismissed from the job</span></p>', '', '', '', '', '', '', '', '', '', 4, '', 1, '149', 149, 0, '', '1', 0),
(720, 79, '1', 50, '1', '<p>&nbsp;<span style=\"color: rgba(41, 41, 41, 0.9); font-family: Poppins, sans-serif; font-size: 18px;\">Carriage inwards can be included in_________.</span></p>', '<p>&nbsp;<span style=\"font-family: Poppins, sans-serif; font-size: 18px;\">Direct expenses</span></p>', '<p>&nbsp;<span style=\"font-family: Poppins, sans-serif; font-size: 18px;\">Current liability</span></p>', '<p>&nbsp;<span style=\"color: rgba(41, 41, 41, 0.9); font-family: Poppins, sans-serif; font-size: 18px;\">Indirect expenses</span></p>', '<p>&nbsp;<span style=\"color: rgba(41, 41, 41, 0.9); font-family: Poppins, sans-serif; font-size: 18px;\">Misc Expenses</span></p>', '', '', '', '', '', '', '', '', '', 0, '', 1, '149', 149, 0, '', '1', 0),
(721, 80, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">What is internet?</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">a single network</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">A collection of unrelated computers</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">interconnection of local area networks</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;interconnection of wide area networks</span></p>', '', '', '', '', '', '', '', '', '', 4, '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">d</span><br style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\" />\r\n<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Explanation: The internet is a global network formed by connecting wide area networks (WANs), enabling worldwide communication and data sharing.</span></p>', 1, '92', 92, 0, '', '1', 0),
(723, 80, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Internet access by transmitting digital data over the wires of a local telephone network is provided by _______</span></p>', '<p><span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">leased line</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">digital subscriber line</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">digital signal line</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">digital leased line</span></p>', '', '', '', '', '', '', '', '', '', 2, '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Answer: b</span><br style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\" />\r\n<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Explanation: DSL (Digital Subscriber Line) is the technology designed to use the existing telephone lines to transport high-bandwidth data to service subscribers. DSL was used to allow the early users access to the internet and it provides dedicated, point-to-point, public network access.</span></p>', 1, '92', 92, 0, '', '1', 0),
(724, 80, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;ISP exchanges internet traffic between their networks by __________</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;internet exchange point</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">subscriber end point</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">isp end point</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;internet end point</span></p>', '', '', '', '', '', '', '', '', '', 1, '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Answer: a</span><br style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\" />\r\n<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Explanation: ISPs exchange internet traffic between their networks by using Internet Exchange Points. ISPs and CDNs are connected to each other at these physical locations are they help them provide better service to their customers.</span></p>', 1, '92', 92, 0, '', '1', 0),
(725, 80, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Which of the following protocols is used in the internet?</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">HTTP</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">DHCP</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">DNS</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;DNS, HTTP and DHCP</span></p>', '', '', '', '', '', '', '', '', '', 4, '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Answer: d</span></p>\r\n<div id=\"target-id6863e80937e5e\" class=\"collapseomatic_content \" style=\"border: 0px; margin: 0px 0px 30px 16px; padding: 0px; color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Explanation: HTTP is used to browse all the websites on the World Wide Web, DHCP is used to allot IPs automatically to the users on the internet, and DNS is used to connect the users to the host servers on the internet based on the Domain Name.</div>\r\n<div></div>', 1, '92', 92, 0, '', '1', 0),
(726, 80, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;The size of an IP address in IPv6 is _________</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">32 bits</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">64 bits</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">128 bits</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">265 bits</span></p>', '', '', '', '', '', '', '', '', '', 3, '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Answer: c</span><br style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\" />\r\n<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Explanation: An IPv6 address is 128 bits long. Therefore, 2128 i.e. 340 undecillion addresses are possible in IPv6. IPv4 has only 4 billion possible addresses and IPv6 would be a brilliant alternative in case IPv4 runs out of possible new addresses.</span></p>', 1, '92', 92, 0, '', '1', 0),
(727, 80, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;Internet works on _______</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">packet switching</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;circuit switching</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;both packet switching and circuit switching</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">data switching</span></p>', '', '', '', '', '', '', '', '', '', 1, '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Answer: a</span><br style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\" />\r\n<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Explanation: Packet switching is the method based on which the internet works. Packet switching features delivery of packets of data between devices over a shared network.</span></p>', 1, '92', 92, 0, '', '1', 0),
(728, 80, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;Which one of the following is not an application layer protocol used in internet?</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">remote procedure call</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;internet relay chat</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">resource reservation protocol</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">local procedure call</span></p>', '', '', '', '', '', '', '', '', '', 3, '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Answer: c</span><br style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\" />\r\n<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Explanation: Resource reservation protocol is a transport layer protocol used on the internet. It operates over IPv4 and IPv6 and is designed to reserve resources required by the network layer protocols.</span></p>', 1, '92', 92, 0, '', '1', 0),
(729, 80, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Which protocol assigns IP address to the client connected in the internet?</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">DHCP</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">IP</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">RPC</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">RSVP</span></p>', '', '', '', '', '', '', '', '', '', 1, '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Answer: a</span><br style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\" />\r\n<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Explanation: DHCP stands for Domain Host Control Protocol. It is responsible to remotely assign IP address to the clients connected to the internet. The server that performs this fuction is called the DHCP server.</span></p>', 1, '92', 92, 0, '', '1', 0);

