INSERT INTO `blogcontents` (`id`, `date_time`, `pid`, `blogcontents`, `descr`, `photo`, `video`, `published_by`, `branch`, `uid`, `status`) VALUES
(4, '16/10/2019 03:33:30', '0', 'STOCK MARKET', '<p>Unique source of Income.&nbsp;</p>', '', '', 'Beer Singh', '1', '1', 1),
(2, '10/09/2019 08:27:51', '1', 'HAPPY DIWALI', '<p>From Wikipedia, the free encyclopedia:</p>\r\n<p>&quot;Deepavali&quot; and &quot;Dipawali&quot; redirect here. For other uses, see Deepavali (disambiguation).</p>\r\n<p>Diwali, Deepavali or Dipavali is a four-to-five day-long (varying as per the Hindu Calendar) festival of lights,&nbsp;which is celebrated by Hindus, Jains, Sikhs and some Buddhists every autumn in the northern hemisphere&nbsp;(spring in southern hemisphere).One of the most popular festivals of Hinduism, Diwali symbolises the&nbsp;spiritual &quot;victory of light over darkness, good over evil and knowledge over ignorance.&quot; Light is a metaphor&nbsp;for knowledge and consciousness.During the celebration, temples, homes, shops and office buildings&nbsp;are brightly illuminated.The preparations, and rituals, for the festival typically last five days, with&nbsp;the climax occurring on the third day coinciding with the darkest night of the Hindu lunisolar month Kartika.&nbsp;In the Gregorian calendar, the festival generally falls between mid-October and mid-November.</p>\r\n<p></p>\r\n<p>In the lead-up to Diwali, celebrants will prepare by cleaning, renovating, and decorating their homes and workplaces.During the climax, revellers adorn themselves in their finest clothes, illuminate the interior and exterior of their&nbsp;homes with diyas (oil lamps or candles), offer puja (worship) to Lakshmi, the goddess of prosperity and wealth, light fireworks, and partake in family feasts, where mithai (sweets) and gifts are shared. Diwali is also a major&nbsp;cultural event for the Hindu, Sikh, Jain, and Buddhist diaspora from the Indian subcontinent.</p>\r\n<p></p>\r\n<p>The five-day festival originated in the Indian subcontinent and is mentioned in early Sanskrit texts. The names of&nbsp;the festive days of Diwali, documented by Qa Kishore, as well as the rituals, vary by region. Diwali is usually celebrated&nbsp;eighteen days after the Dussehra (Dasara, Dasain) festival, with Dhanteras, or the regional equivalent, marking the first&nbsp;day of the festival when celebrants prepare by cleaning their homes and making decorations on the floor, such as rangoli.</p>\r\n<p>The second day is Naraka Chaturdashi, or the regional equivalent which for Hindus in the south of India is Diwali proper.&nbsp;Western, central, eastern and northern Indian communities observe main day of Diwali on the third day i.e. the day of&nbsp;Lakshmi Puja and the darkest night of the traditional month. In some parts of India, the day after Lakshmi Puja is marked&nbsp;with the Govardhan Puja and Balipratipada (Padwa), which is dedicated to the relationship between wife and husband.&nbsp;Some Hindu communities mark the last day as Bhai Dooj or the regional equivalent, which is dedicated to the bond between&nbsp;sister and brother, while other Hindu and Sikh craftsmen communities mark this day as Vishwakarma Puja and observe it&nbsp;by performing maintenance in their work spaces and offering prayers.</p>\r\n<p></p>\r\n<p>Some other faiths in India also celebrate their respective festivals alongside Diwali. The Jains observe their own Diwali,&nbsp;which marks the final liberation of Mahavira,the Sikhs celebrate Bandi Chhor Divas to mark the release of Guru Hargobind&nbsp;from a Mughal Empire prison,while Newar Buddhists, unlike other Buddhists, celebrate Diwali by worshipping Lakshmi,while&nbsp;the Bengali Hindus generally celebrate Diwali, by worshipping Goddess Kali.The main day of the festival of Diwali i.e&nbsp;the day of Lakshmi Puja is an official holiday in Fiji,Guyana,India, Malaysia (except Sarawak),Mauritius, Myanmar,NepalSingapore,Sri Lanka, Suriname, and Trinidad and Tobago.</p>\r\n<p></p>', '1571972595644.jpg', '', 'SHAFAT ALI', '1', '1', 1);
