(1, 'CCA', '1', 'Certificate In Computer Awareness (CCA)', '<div><strong><span style=\"color: rgb(255, 0, 0);\"><span style=\"font-size: x-large;\">Certificate In Computer Awareness (CCA)</span></span></strong></div>\r\n<div><span style=\"font-size: medium;\"><strong>Eligibility - 8th&nbsp; &nbsp; &nbsp; &nbsp; Duration - 3 months&nbsp; &nbsp; &nbsp; &nbsp;Code - C10</strong></span></div>\r\n<ul>\r\n    <li>Computer Concept &amp; Fundamentals</li>\r\n    <li>OS ( Dos, Windows)</li>\r\n    <li>Microsoft Office ( Word , Excel )</li>\r\n    <li>Introduction Of Internet</li>\r\n    <li>Practical &amp; Project</li>\r\n</ul>', '', '1630547554456.jpg', '3', '5000', '', '1', '1', 1, 0, '100', '', '', '', 0),
(2, 'CIA', '1', 'Certificate In Internet Application (CIA)', '<p>&nbsp;</p>\r\n<p class=\"MsoNormal\" style=\"text-align: left; line-height: normal;\"><b><span style=\"font-size:18.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;mso-fareast-font-family:&#10;&quot;Times New Roman&quot;;color:red;mso-font-kerning:18.0pt\">Certificate In Internet Application (CIA)<o:p></o:p></span></b></p>\r\n<p class=\"MsoNormal\" style=\"text-align: left; line-height: normal;\"><b><span style=\"font-size:15.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;mso-fareast-font-family:&#10;&quot;Times New Roman&quot;\">Eligibility - 10<sup>th</sup><span style=\"mso-spacerun:yes\">&nbsp; </span>Duration - 3 months<span style=\"mso-spacerun:yes\">&nbsp; </span>Code No - C11<o:p></o:p></span></b></p>\r\n<ul>\r\n    <li><span style=\"font-size: medium;\"><b style=\"mso-bidi-font-weight:normal\"><span style=\"line-height: 150%; font-family: &quot;Times New Roman&quot;, serif;\">Computer Concept &amp; Fundamentals</span></b></span><b style=\"mso-bidi-font-weight:normal\"><span style=\"font-size:10.0pt;&#10;     line-height:150%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;mso-fareast-font-family:&#10;     &quot;Times New Roman&quot;\"><o:p></o:p></span></b></li>\r\n    <li><span style=\"font-size: medium;\"><b style=\"mso-bidi-font-weight:normal\"><span style=\"line-height: 150%; font-family: &quot;Times New Roman&quot;, serif;\">Operating System ( Dos, Windows)</span></b></span><b style=\"mso-bidi-font-weight:normal\"><span style=\"font-size:10.0pt;&#10;     line-height:150%;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;mso-fareast-font-family:&#10;     &quot;Times New Roman&quot;\"><o:p></o:p></span></b></li>\r\n    <li><span style=\"font-size: medium;\"><b style=\"mso-bidi-font-weight:normal\"><span style=\"line-height: 150%; font-family: &quot;Times New Roman&quot;, serif;\">Internet Technology &amp; E-Mail</span></b></span><b style=\"mso-b