(3, 'SE1', '8', 'Diploma In Solar Energy Technician (DSET)', '<p>&nbsp;</p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom:0in;margin-bottom:.0001pt;line-height:&#10;15.75pt;vertical-align:baseline\"><b><span style=\"font-size:11.5pt;mso-bidi-font-size:&#10;11.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;mso-fareast-font-family:&quot;Times New Roman&quot;;&#10;color:black;mso-themecolor:text1\">Course Code- SE1<span style=\"mso-spacerun:yes\">&nbsp;&nbsp; </span>Duration- 1 Year<span style=\"mso-spacerun:yes\">&nbsp;&nbsp;&nbsp; </span>Eligibility: 10<sup>th</sup><o:p></o:p></span></b></p>\r\n<p class=\"MsoNormal\"><b style=\"mso-bidi-font-weight:normal\"><span style=\"font-size:18.0pt;mso-bidi-font-size:11.0pt;line-height:115%;font-family:&#10;&quot;Times New Roman&quot;,&quot;serif&quot;;color:red\">Diploma In Solar Energy Technician (DSET)<o:p></o:p></span></b></p>\r\n<p class=\"MsoListParagraphCxSpFirst\" style=\"text-indent:-.25in;mso-list:l0 level1 lfo1\"><!--[if !supportLists]--><span style=\"font-family:Wingdings;mso-fareast-font-family:Wingdings;mso-bidi-font-family:&#10;Wingdings\"><span style=\"mso-list:Ignore\">&Oslash;<span style=\"font:7.0pt &quot;Times New Roman&quot;\">&nbsp; </span></span></span><!--[endif]--><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Solar Energy and Photovoltaic<o:p></o:p></span></p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"text-indent:-.25in;mso-list:l0 level1 lfo1\"><!--[if !supportLists]--><span style=\"font-family:Wingdings;mso-fareast-font-family:Wingdings;mso-bidi-font-family:&#10;Wingdings\"><span style=\"mso-list:Ignore\">&Oslash;<span style=\"font:7.0pt &quot;Times New Roman&quot;\">&nbsp; </span></span></span><!--[endif]--><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Maintenance and Troubleshooting<o:p></o:p></span></p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"text-indent:-.25in;mso-list:l0 level1 lfo1\"><!--[if !supportList