(64, 'ACP2', '10', 'CERTIFICATE IN REFLEXOLOGY AND ACUPRESSURE', '<p>&nbsp;</p>\r\n<h4 style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 0.5rem; font-family: Poppins, sans-serif; font-weight: 500; line-height: 1.2em; color: rgb(31, 31, 31); font-size: 18px;\"><a href=\"https://www.rpkvs.com/course.php#\" style=\"box-sizing: border-box; text-decoration-line: none; background-color: transparent; transition: all 0.3s ease 0s; outline: none medium;\">CERTIFICATE IN REFLEXOLOGY AND ACUPRESSURE</a></h4>\r\n<ul style=\"box-sizing: border-box; margin: 0px; padding: 0px; color: rgb(33, 37, 41); font-family: Poppins, sans-serif; font-size: 16px;\">\r\n    <li style=\"box-sizing: border-box; list-style: none;\"><span style=\"box-sizing: border-box; font-size: 15px; font-weight: 600; width: 90px; float: left;\"><span style=\"box-sizing: border-box; font-weight: bolder; color: rgb(255, 94, 19);\">Duration :</span></span>6 MONTHS</li>\r\n    <li style=\"box-sizing: border-box; list-style: none;\"><span style=\"box-sizing: border-box; font-size: 15px; font-weight: 600; width: 90px; float: left;\"><span style=\"box-sizing: border-box; font-weight: bolder; color: rgb(255, 94, 19);\">Eligibility :</span></span>10th/12th Pass( PCB/PCM)</li>\r\n</ul>', '', '1628072034935.jpg', '6', '800', '', '1', '1', 1, 0, '800', '', '', '', 0),
(65, 'ACP04', '10', 'DIPLOMA IN ACUPUNCTURE THERAPY', '<p>&nbsp;</p>\r\n<h4 style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 0.5rem; font-family: Poppins, sans-serif; font-weight: 500; line-height: 1.2em; color: rgb(31, 31, 31); font-size: 18px;\"><a href=\"https://www.rpkvs.com/course.php#\" style=\"box-sizing: border-box; text-decoration-line: none; background-color: transparent; transition: all 0.3s ease 0s; outline: none medium;\">DIPLOMA IN ACUPUNCTURE THERAPY</a></h4>\r\n<ul style=\"box-sizing: border-box; margin: 0px; padding: 0px; color: rgb(33, 37, 41); font-family: Poppins, sans-serif; font-size: 16px;\">\r\n    <li style=\"box-sizing: border-box; list-style: none;\"><span style=\"box-sizing: border-box; font-size: 15px; font-weight: 600; width: 90px; float: left;\"><span style=\"box-sizing: border-box; font-weight: bolder; color: rgb(255, 94, 19);\">Duration :</span></span>1 YEAR</li>\r\n    <li style=\"box-sizing: border-box; list-style: none;\"><span style=\"box-sizing: border-box; font-size: 15px; font-weight: 600; width: 90px; float: left;\"><span style=\"box-sizing: border-box; font-weight: bolder; color: rgb(255, 94, 19);\">Eligibility :</span></span>10th/12th Pass( PCB/PCM)</li>\r\n</ul>', '', '1628072507194.jpg', '12', '800', '', '1', '1', 1, 0, '800', '', '', '', 0),
(66, 'ACP05', '10', 'ADVANCED DIPLOMA IN ACUPUNCTURE', '<p>&nbsp;</p>\r\n<h4 style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 0.5rem; font-family: Poppins, sans-serif; font-weight: 500; line-height: 1.2em; color: rgb(31, 31, 31); font-size: 18px;\"><a href=\"https://www.rpkvs.com/course.php#\" style=\"box-sizing: border-box; color: rgb(31, 31, 31); text-decoration-line: none; background-color: transparent; transition: all 0.3s ease 0s; outline: none medium;\">ADVANCED DIPLOMA IN ACUPUNCTURE</a></h4>\r\n<ul style=\"box-sizing: border-box; margin: 0px; padding: 0px; color: rgb(33, 37, 41); font-family: Poppins, sans-serif; font-size: 16px;\">\r\n    <li style=\"box-sizing: border-box; list-style: none;\"><span style=\"box-sizing: border-box; font-size: 15px; font-weight: 600; width: 90px; float: left;\"><span style=\"box-sizing: border-box; font-weight: bolder; color: rgb(255, 94, 19);\">Duration :</span></span>1 YEAR</li>\r\n    <li style=\"box-sizing: border-box; list-style: none;\"><span style=\"box-sizing: border-box; font-size: 15px; font-weight: 600; width: 90px; float: left;\"><span style=\"box-sizing: border-box; font-weight: bolder; color: rgb(255, 94, 19);\">Eligibility :</span></span>10th/12th Pass( PCB/PCM)</li>\r\n</ul>', '', '1628072195212.jpg', '12', '1000', '', '1', '1', 1, 0, '1000', '', '', '', 0),
(67, 'ACP06', '10', '  Master Diploma in Acupressure Therapy (M.D.Acu.)', '<table border=\"1\" cellpadding=\"0\" cellspacing=\"0\" style=\"font-family: Verdana, Arial, Helvetica, sans-serif; width: 700px;\">\r\n    <tbody>\r\n        <tr>\r\n            <td style=\"font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 14px; height: 12px; width: 501px;\">\r\n            <p><span style=\"font-size: 18px;\"><span style=\"font-family: &quot;times new roman&quot;, times, serif;\">&nbsp;&nbsp;<span style=\"color: rgb(255, 0, 0);\"><strong>Master Diploma in Acupressure Therapy (M.D.Acu.)</strong></span></span></span></p>\r\n            </td>\r\n        </tr>\r\n        <tr>\r\n            <td style=\"font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 14px; height: 12px; width: 199px;\">\r\n            <table border=\"1\" cellpadding=\"0\" cellspacing=\"0\" style=\"width: 700px;\">\r\n                <tbody>\r\n                    <tr>\r\n                        <td colspan=\"2\" style=\"font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 14px; height: 10px; width: 700px;\">\r\n                        <p style=\"text-align: center;\"><span style=\"font-size: 18px;\"><span style=\"font-family: &quot;times new roman&quot;, times, serif;\"><span style=\"color: rgb(255, 0, 0);\"><strong>SYLLABUS :</strong></span></span></span></p>\r\n                        <h3 style=\"text-align: center;\"><span style=\"color: rgb(0, 0, 255);\"><span style=\"font-size: 16px;\">Acupressure Master Course Level - II&nbsp; &nbsp; &nbsp;Special Reference to Meridianlogy</span></span></h3>\r\n                        </td>\r\n                    </tr>\r\n                    <tr>\r\n                        <td colspan=\"2\" style=\"font-family: Verdana, Arial, Helvetica, sans-serif; font-size: 14px; height: 38px; width: 700px;\">\r\n                        <ol>\r\n                            <li><span style=\"font-size: 18px;\"><span style=\"font-family: &quot;times new roman&quot;, times, serif;\">Human Anatomy with Reference to Acupressure.</span></span></li>\r\n                            <li><span style=\"font-size: 18px;\"><span style=\"font-family: &quot;times new roman&quot;, times, serif;\">History, Philosophy &amp; Principles of&nbsp;</span></span><span style=\"font-family: &quot;times new roman&quot;, times, serif; font-size: 18px;\">Acupressure T</span><span style=\"font-size: 18px;\"><span style=\"font-family: &quot;times new roman&quot;, times, serif;\">herapy.</span></span></li>\r\n                            <li><span style=\"font-size: 18px;\"><span style=\"font-family: &quot;times new roman&quot;, times, serif;\">Advance Reflexology (Face&nbsp;&amp; Spine).</span></span></li>\r\n                            <li><span style=\"font-size: 18px;\"><span style=\"font-family: &quot;times new roman&quot;, times, serif;\">Yin-Yang Concept &amp; Five Element Theory.</span></span></li>\r\n                            <li><span style=\"font-size: 18px;\"><span style=\"font-family: &quot;times new roman&quot;, times, serif;\">Meridianlogy 14 Channel.</span></span></li>\r\n                            <li><span style=\"font-family: &quot;times new roman&quot;, times, serif;\"><span style=\"font-size: 18px;\">Method of Pressure - Stimulation, Tonification &amp; Sedation.</span></span></li>\r\n                            <li><span style=\"font-family: &quot;times new roman&quot;, times, serif;\"><span style=\"font-size: 18px;\">Important Meridian Point, Diagnosis.</span></span></li>\r\n                            <li><span style=\"font-family: &quot;times new roman&quot;, times, serif;\"><span style=\"font-size: 18px;\">Disease &amp; Treatment Methods by Acu. Point.</span></span></li>\r\n                            <li><span style=\"font-family: &quot;times new roman&quot;, times, serif;\"><span style=\"font-size: 18px;\">Uses of Various Acupressure&nbsp;Instruments.&nbsp;</span></span></li>\r\n                            <li><span style=\"font-size: 18px;\"><span style=\"font-family: &quot;times new roman&quot;, times, serif;\">General Knowledge of Magnet,&nbsp;Colour,&nbsp;General Food Therapy.</span></span></li>\r\n                        </ol>\r\n                        </td>\r\n                    </tr>\r\n                </tbody>\r\n            </table>\r\n            </td>\r\n        </tr>\r\n    </tbody>\r\n</table>', '', '1629519148688.jpg', '12', '8900', '', '1', '1', 1, 0, '2500', '', '', '', 0),
