(69, 'PGDFSDM', '7', 'PG DIPLOMA IN FIRE SAFETY & DISASTER MANAGEMENT', '<p>&nbsp;</p>\r\n<p class=\"MsoNormal\"><span style=\"color: rgb(255, 0, 0);\"><b style=\"mso-bidi-font-weight:normal\"><span style=\"font-size: 16pt; font-family: &quot;Times New Roman&quot;, serif;\">PG DIPLOMA IN FIRE SAFETY &amp; DISASTER</span></b></span><b style=\"mso-bidi-font-weight:normal\"><span style=\"font-size:16.0pt;mso-bidi-font-size:11.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\"><o:p></o:p></span></b></p>\r\n<p class=\"MsoNormal\"><span style=\"color: rgb(255, 0, 0);\"><b style=\"mso-bidi-font-weight:normal\"><span style=\"font-size: 16pt; font-family: &quot;Times New Roman&quot;, serif;\">MANAGEMENT</span></b></span><span style=\"font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\"><o:p></o:p></span></p>\r\n<p class=\"MsoNormal\"><b style=\"mso-bidi-font-weight:normal\"><span style=\"font-size:12.0pt;mso-bidi-font-size:11.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Course Code: PGDFSDM&nbsp;<o:p></o:p></span></b></p>\r\n<p class=\"MsoNormal\"><b style=\"mso-bidi-font-weight:normal\"><span style=\"font-size:12.0pt;mso-bidi-font-size:11.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">Duration of Course : 1 Year<o:p></o:p></span></b></p>\r\n<p class=\"MsoNormal\"><o:p>&nbsp;</o:p></p>\r\n<p class=\"MsoNormal\"><b style=\"mso-bidi-font-weight:normal\"><span style=\"font-size:12.0pt;mso-bidi-font-size:11.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">PGDFSDM-101<span style=\"mso-tab-count:2\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </span>FUNDAMENTALS OF FIRE SCIENCE<o:p></o:p></span></b></p>\r\n<p class=\"MsoNormal\"><b style=\"mso-bidi-font-weight:normal\"><span style=\"font-size:12.0pt;mso-bidi-font-size:11.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;\">PGDFSDM-102 <span style=\"mso-tab-count:1\">&nbsp;&nbsp; </span><span style=\"mso-