(106, 'CPYTHON', '1', 'Certificate In Python (CIP)', '<p><strong><span style=\"color: rgb(255, 0, 0);\"><span style=\"font-size: x-large;\"><span style=\"font-family: &quot;Times New Roman&quot;;\">Certificate In Python (CIP)</span></span></span></strong></p>\r\n<p><span style=\"color: rgb(0, 0, 255);\"><strong><span style=\"font-size: large;\"><span style=\"font-family: &quot;Times New Roman&quot;;\">Eligibility- 10th&nbsp; &nbsp; Duration- 2 months&nbsp; &nbsp; &nbsp;Code No &ndash; CIP16</span></span></strong></span></p>\r\n<p><strong><span style=\"font-size: larger;\"><span style=\"font-family: &quot;Times New Roman&quot;;\">&Oslash; Introduction to Python</span></span></strong></p>\r\n<p><strong><span style=\"font-size: larger;\"><span style=\"font-family: &quot;Times New Roman&quot;;\">&Oslash; Introduction to Script</span></span></strong></p>\r\n<p><strong><span style=\"font-size: larger;\"><span style=\"font-family: &quot;Times New Roman&quot;;\">&Oslash; Environment set up&nbsp;</span></span></strong></p>\r\n<p><strong><span style=\"font-size: larger;\"><span style=\"font-family: &quot;Times New Roman&quot;;\">&Oslash; Writing first program in Python</span></span></strong></p>\r\n<p><strong><span style=\"font-size: larger;\"><span style=\"font-family: &quot;Times New Roman&quot;;\">&Oslash; Basics</span></span></strong></p>\r\n<p><strong><span style=\"font-size: larger;\"><span style=\"font-family: &quot;Times New Roman&quot;;\">&Oslash;&nbsp; Datatypes</span></span></strong></p>\r\n<p><strong><span style=\"font-size: larger;\"><span style=\"font-family: &quot;Times New Roman&quot;;\">&Oslash;&nbsp; Operators</span></span></strong></p>\r\n<p><strong><span style=\"font-size: larger;\"><span style=\"font-family: &quot;Times New Roman&quot;;\">&Oslash;&nbsp; Input and Output</span></span></strong></p>\r\n<p><strong><span style=\"font-size: larger;\"><span style=\"font-family: &quot;Times New Roman&quot;;\">&Oslash;&nbsp; Control Statements</span></span></strong></p>\r\n<p><strong><span style=\"font-size: larger;\"><span style=\"font-family: &quot;Times New Roman&quot;;\">&Oslash;&nbsp; Arrays in Python</span></span></strong></p>\r\n<p><strong><span style=\"font-size: larger;\"><span style=\"font-family: &quot;Times New Roman&quot;;\">&Oslash;&nbsp; Strings and Characters</span></span></strong></p>\r\n<p></p>\r\n<p><strong><span style=\"font-size: larger;\"><span style=\"font-family: &quot;Times New Roman&quot;;\">&Oslash;&nbsp; Functions</span></span></strong></p>\r\n<p><strong><span style=\"font-size: larger;\"><span style=\"font-family: &quot;Times New Roman&quot;;\"><br />\r\n</span></span></strong></p>', '', '', '2', '6000', '', '1', '1', 1, 0, '100', '', '', '', 0);
