(9, 'pmkvy', '<h4><span style=\"font-family: &quot;Comic Sans MS&quot;;\"><span style=\"background-color: yellow;\">&nbsp;AUTHORISED TRAINING PARTNER FOR PMKVY. Trust is Authorised Training Partner for&nbsp;</span></span><span style=\"font-family: &quot;Comic Sans MS&quot;;\"><span style=\"background-color: yellow;\">PMKVY Retail SSC (RASCI), It/ITes NASSCOM</span></span></h4>', '', 0, '1', '1', ''),
(10, 'franchisee', '<h3><span style=\"font-family: &quot;Comic Sans MS&quot;;\"><span style=\"background-color: lime;\"><span style=\"color: rgb(48, 48, 48); font-size: 14px;\">FRANCHISE REQUIRED</span></span></span></h3>\r\n<h3><span style=\"font-family: &quot;Comic Sans MS&quot;;\"><span style=\"background-color: lime;\">SEND FRANCHISE REQUEST All OVER INDIA LOCATIONS&nbsp;</span></span></h3>', '', 1, '1', '1', ''),
(11, 'new center', '<h3></h3>\r\n<p><span style=\"background-color: rgb(0, 0, 255);\"> </span></p>\r\n<h3><strong>FRANCHISE REQUIRED</strong></h3>', '', 1, '1', '1', ''),
(12, 'New Year Offer 2024', '<p></p>\r\n<p><span style=\"font-family: &quot;Times New Roman&quot;;\"> </span></p>\r\n<p><span style=\"background-color: rgb(0, 0, 0);\"><span style=\"color: rgb(255, 0, 255);\"><strong>New Year Offer 2024</strong></span></span></p>\r\n<p></p>\r\n<h3></h3>\r\n<h3><span style=\"background-color: rgb(255, 0, 0);\"><span style=\"color: rgb(255, 255, 255);\"><span style=\"font-family: Arial;\"><strong>&nbsp;All Course 10% Discount&nbsp;</strong></span></span></span></h3>', '', 1, '1', '1', '');
INSERT INTO `page` (`id`, `parent_id`, `name`, `weight`, `pile_height`, `imname`, `show_on`, `status`, `descr`) VALUES
(1, 0, 'About Us', 1, '', '', 0, 1, '<div style=\"text-align: justify;\">RGPI belives in the foundation of technology, that Computer Science has brought new opportunties and challenges to traditional study style, and has changed the foundational concepts in education .futher major progress in computer science would only be fessible when education system provides sound foundationsfor areas of software engineering and knowledge engineering.</div>\r\n<div style=\"text-align: justify;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Ram Group of Professional Institute has taken up that responsibility for the development of student in the field of computer science.</div>\r\n<div style=\"text-align: justify;\">Now a days whole world moving towards development, in this way computer play is most important role. In recent future computer will become more useful. We can feel the necessity of computer in all fields. In this developing era, mental development of kids is too good. So CEC has prepared a syllabus of computer education for class 5th to 10th and higher computer education. This syllabus is prepared under technical view to manage a quality computer education all over India. Duration of each syllabus is One month to two years , and a grading certificate &amp; Mark sheet will be issued through the council. home</div>\r\n<div style=\"text-align: justify;\"></div>\r\n<p style=\"text-align: justify;\">Establishment of this council has been done to achieve the motto of &ldquo;SARVA SIKSHA AVHIYAAN&rdquo; (in the field of computer) , through which computer education can provided with favorably syllabus. After 10th class higher education of computer has provided on Coaching centers. Council has oathed /constrained for making bright future of all students Wisdom of computer is necessary.&nbsp;</p>'),
(2, 0, 'Welcome to Gokulshree School Of Management And Technology Pvt Ltd', 2, '', '1632892464871.jpg', 0, 0, '<div>\r\n<div style=\"background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><font face=\"Tahoma\"><span style=\"font-size: 18.6667px;\"><b>Gokulshree School Of Management And Technology Pvt Ltd is&nbsp; An Autonomous Body Registered under SR Act, 9(1)2012&nbsp;</b></span></font><span style=\"font-family: Tahoma;\"><span style=\"font-size: 14pt;\">has been registered under the Government of India, working in different fields of Programme &amp; Commercial Training sponsored by the Central Government by taking a vow to approach every class of Youth in the society. The Organization is also certified by ISO 9001: 2015. The Institute &amp; the Organization is also Registered under the&nbsp;</span></span><b style=\"font-family: Tahoma; font-size: 18.6667px;\">&nbsp;An Autonomous Body Registered under SR Act, 9(1)2012</b><span style=\"font-family: Tahoma;\"><span style=\"font-size: 14pt;\">, Ministry of Micro, Small &amp; Medium Enterprises (MSME)<b>,&nbsp;</b><strong><span style=\"background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><span style=\"font-weight: normal;\">NCS &ndash; National career Service</span></span></strong><strong><span style=\"background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\">,</span></strong></span><strong><span style=\"background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\">&nbsp;</span></strong><span style=\"font-size: 14pt;\">Ministry of Labour &amp; Employment and Ministry of AYUSH and is accredited to conduct the various fields of technical programs sponsored by both the Govt.</span></span></div>\r\n<div style=\"background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; margin: 0in 0in 6.25pt;\"><b style=\"font-family: Tahoma; font-size: 18.6667px;\">Gokulshree School Of Management And Technology Pvt Ltd is&nbsp;&nbsp;An Autonomous Body Registered under SR Act, 9(1)2012</b><font face=\"Tahoma\"><span style=\"font-size: 18.6667px;\"><b>&nbsp;</b></span></font><span style=\"font-family: Tahoma;\"><span style=\"font-size: 14pt;\">&nbsp;The main function of the society is to provide higher technical education in nominal charges for every group of society of Urban &amp; Rural areas all over India and get success in computer revolution which is the main dream of Indian Govt..</span></span></div>\r\n</div>\r\n<p></p>'),
(16, 0, ' TESTIMONIALS', 5, '', '1633671869647.jpg', 0, 0, ''),
(18, 1, 'Our Profile', 1, '', '', 0, 1, '<div style=\"background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\">\r\n<div style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; color: rgb(119, 119, 119); font-family: Cabin, sans-serif; font-size: 16px; text-align: justify; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><span style=\"color: rgb(0, 0, 0);\"><font face=\"Tahoma\" style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none;\"><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-size: 18.6667px;\"><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-weight: 700;\">GSMT is&nbsp; An Autonomous Body Registered under SR Act, 9(1)2012&nbsp;</span></span></font><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-family: Tahoma;\"><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-size: 14pt;\">has been registered under the Government of India, working in different fields of Programme &amp; Commercial Training sponsored by the Central Government by taking a vow to approach every class of Youth in the society. The Organization is also certified by ISO 9001: 2015. The Institute &amp; the Organization is also Registered under the&nbsp;</span></span><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-weight: 700; font-family: Tahoma; font-size: 18.6667px;\">&nbsp;An Autonomous Body Registered under SR Act, 9(1)2012</span><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-family: Tahoma;\"><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-size: 14pt;\">, Ministry of Micro, Small &amp; Medium Enterprises (MSME)<span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-weight: 700;\">,&nbsp;</span><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-weight: 700;\"><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-weight: normal;\">NCS &ndash; National career Service</span></span></span><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-weight: 700;\"><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\">,</span></span></span><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-weight: 700;\"><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\">&nbsp;</span></span><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-size: 14pt;\">Ministry of Labour &amp; Employment and Ministry of AYUSH and is accredited to conduct the various fields of technical programs sponsored by both the Govt.</span></span></span></div>\r\n<div style=\"box-sizing: border-box; margin: 0in 0in 6.25pt; padding: 0px; border: none; outline: none; color: rgb(119, 119, 119); font-family: Cabin, sans-serif; font-size: 16px; text-align: justify; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;\"><span style=\"color: rgb(0, 0, 0);\"><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-weight: 700; font-family: Tahoma; font-size: 18.6667px;\">GSMT is&nbsp;&nbsp;An Autonomous Body Registered under SR Act, 9(1)2012</span><font face=\"Tahoma\" style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none;\"><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-size: 18.6667px;\"><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-weight: 700;\">&nbsp;</span></span></font><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-family: Tahoma;\"><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-size: 14pt;\">&nbsp;The main function of the society is to provide higher technical education in nominal charges for every group of society of Urban &amp; Rural areas all over India and get success in computer revolution which is the main dream of Indian Govt..</span></span></span></div>\r\n</div>'),
(19, 1, 'Chairman Message', 2, '', '', 0, 1, '<div style=\"text-align: center;\"><span style=\"font-family: Verdana;\"><span style=\"font-size: medium;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span><strong><span style=\"font-size: medium;\"> FROM THE DESK OF DIRECTORS</span></strong></span></div>\r\n<div style=\"text-align: justify; \"><span style=\"font-family: Verdana;\"><span style=\"font-size: medium;\">Every Single human is enriched with some talent from inside &quot;</span></span><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-weight: 700; color: rgb(119, 119, 119); font-family: Tahoma; font-size: 18.6667px; text-align: justify;\">Gokulshree School Of Management And Technology Private Limited</span><span style=\"font-family: Verdana; font-size: medium;\">&quot;&rsquo; focus on growth of every one with all possible talents He/She comes with. Our pedagogy ensures a holistic growth model of&nbsp;</span><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-weight: 700; color: rgb(119, 119, 119); font-family: Tahoma; font-size: 18.6667px;\">GSMT</span><span style=\"font-size: medium; font-family: Verdana;\">. The Indian corporate sector today is going through a whirl wide change in terms of technology and consumer expectations have placed heavy demands on business origination that have to keep adopting themselves to these rapid changes.&nbsp; To manage such business institute are required to produce future computer educated people. Our aim is to empower individuals intellectually enable them to develop their full potential&nbsp; by enhancing competencies, culture and commitment and contribution to achievement of professional excellence instead of waiting for time to bring to our lives, let us take one right step ahead let us not wait for big things to happen.&nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</span></div>\r\n<div></div>\r\n<div><span style=\"font-family: Verdana;\"><span style=\"font-size: medium;\">&nbsp; &quot;</span></span><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-weight: 700; color: rgb(119, 119, 119); font-family: Tahoma; font-size: 18.6667px; text-align: justify;\">GSMT</span><span style=\"font-size: medium; font-family: Verdana;\">&quot; with many centers all over India aims to provide learning opportunity as well as earning opportunity. In our endeavor to promote greater transparency and accountability through increased use of technology and online services, we would like to request the users to provide their valuable feedback, as we believe that quality is not a destination, but is a journey to improve.</span></div>\r\n<div><span style=\"font-family: Verdana;\"><span style=\"font-size: medium;\">&nbsp; We are committed to offers excellent minds and talents in order to be instrumental, by putting in our candid efforts, in the building process of our NATION.</span></span></div>\r\n<div style=\"text-align: center;\"><span style=\"font-family: Verdana;\"><span style=\"font-size: medium;\">&nbsp; &nbsp;&nbsp;</span></span><span style=\"font-family: Verdana;\"><span style=\"color: rgb(0, 0, 128);\"><strong><span style=\"font-size: medium;\">with best wishes&hellip;&hellip;&hellip;&hellip;&hellip;&hellip;&hellip;.</span></strong></span></span></div>\r\n<div><span style=\"font-family: Verdana;\"><span style=\"font-size: medium;\"><br />\r\n</span></span></div>\r\n<div><span style=\"font-family: Verdana;\"><span style=\"font-size: medium;\"><br />\r\n</span></span></div>\r\n<div><strong><span style=\"font-family: Verdana;\"><span style=\"font-size: medium;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; CHAIRMAN&nbsp;</span></span></strong></div>\r\n<div><span style=\"color: rgb(255, 0, 0);\"><strong><span style=\"font-family: Verdana;\"><span style=\"font-size: medium;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span></span></strong></span><font color=\"#ff0000\" face=\"Verdana\" size=\"3\"><b>AJEET KUMAR</b></font></div>'),
(20, 1, 'Our Vision & Mission', 3, '', '', 0, 1, '<div><strong><span style=\"font-family: Verdana;\"><span style=\"font-size: medium;\">Vision</span></span></strong></div>\r\n<div><span style=\"font-family: Verdana;\"><span style=\"font-size: medium;\">&quot;To satisfy the aspiration of youth force, who want to lead nation towards prosperity through techno-economic development. To aim at building a comprehensive academic institute which values Service through high quality education</span></span></div>\r\n<div><strong><span style=\"font-family: Verdana;\"><span style=\"font-size: medium;\"><br />\r\n</span></span></strong></div>\r\n<div><strong><span style=\"font-family: Verdana;\"><span style=\"font-size: medium;\">Mission</span></span></strong></div>\r\n<div><span style=\"font-family: Verdana;\"><span style=\"font-size: medium;\">To open the minds of students to the I T&amp; computer course all well as diploma &amp; degree courses oriented knowledge, by Imparting quality education to them in the field through state of take best advantage of their educational opportunities preparing them for high level courses in the even expanding field of computer education.</span></span></div>\r\n<div><span style=\"font-family: Verdana;\"><span style=\"font-size: medium;\"><br />\r\n</span></span></div>\r\n<div><strong><span style=\"font-family: Verdana;\"><span style=\"font-size: medium;\">Objective</span></span></strong></div>\r\n<div><span style=\"font-family: Verdana;\"><span style=\"font-size: medium;\">The Objective of&nbsp;</span></span><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-weight: 700; color: rgb(119, 119, 119); font-family: Tahoma; font-size: 18.6667px; text-align: justify;\">GSMT</span><span style=\"font-family: Verdana;\"><span style=\"font-size: medium;\">&nbsp;is that provide Education Every Person of INDIA. There are many Institute of Computer Education but we are the unique to see this vision for our country and our students</span></span></div>\r\n<div><span style=\"font-family: Verdana;\"><span style=\"font-size: medium;\"><br />\r\n</span></span></div>\r\n<p><span style=\"font-family: Verdana;\"><span style=\"font-size: medium;\">&nbsp;</span></span></p>'),
(22, 0, 'Account Details', 6, '', '1723732925719.png', 0, 0, '<h4 class=\"modal-title\" style=\"box-sizing: border-box; font-family: Raleway, Arial, Helvetica, sans-serif; font-weight: 500; line-height: 1.42857; color: rgb(255, 255, 255); margin: 0px; font-size: 18px;\"><a href=\"/uploads/file/2_0(1).jpg\"><img src=\"/uploads/file/2_0(1).jpg\" alt=\"\" /></a></h4>'),
(23, 0, 'Policy', 7, '123', '1627204894737.jpg', 0, 0, '<p>&nbsp;adca</p>'),
(24, 23, 'Privacy Policy', 1, '', '', 0, 1, '<p>&nbsp;<strong style=\"text-align: justify;\">1. What information is collected?</strong></p>\r\n<p style=\"text-align: justify;\">We require customers who register to use the services offered on our Site (collectively, the &quot;Service&quot;) to give us contact information, such as their name, address, phone number, and e-mail address. If you choose to pay for any of the online or offline courses or study materials offered for sale through this website, billing information such as billing name and address, and credit card number will be collected to complete the transaction.</p>\r\n<p style=\"text-align: justify;\">When you browse our website or our blogs, we also automatically receive your computers internet protocol (IP) address in order to provide us with information that helps us learn about your browser and operating system.</p>\r\n<p style=\"text-align: justify;\"><strong>2. Consent for electronic communcation</strong></p>\r\n<p style=\"text-align: justify;\">If you have registered for any of our services that requires you to provide us with your email, you consent to receiving electronic communications from GSMT Institute. These communications will include notices about your account (e.g., activation of account, expiration of account and receiving e-mails and other transactional information) and information concerning or related to our service, such as new product launch or other announcements, or offerings. These communications are part of your relationship with M.S. Baijnath Institute.</p>\r\n<p style=\"text-align: justify;\">In order to tailor our subsequent communications to you and continuously improve our products and services (including registration), we may ask you to provide us with information regarding your personal or professional interests, experience with our products and services, and more detailed contact preferences. Customers and visitors always have the option of choosing not to provide us with this information. Not providing this additional information will in no way affect the promised delivery of services.</p>\r\n<p style=\"text-align: justify;\">If we ask for your personal information for a secondary reason, like marketing, we will either ask you directly for your expressed consent, or provide you with an opportunity to say no.</p>\r\n<p style=\"text-align: justify;\"><strong>How can you withdraw your consent?</strong></p>\r\n<p style=\"text-align: justify;\">If after you opt-in to receive marketing messages, you change your mind, you may withdraw your consent for us to contact you, for the continued collection, use or disclosure of your information, at anytime, by contacting us at gokulshreeschool@gmail.com in&nbsp;or at:</p>\r\n<p style=\"text-align: start;\"><span style=\"color: rgb(255, 0, 0);\"><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-weight: 700; font-family: Tahoma; font-size: 18.6667px; text-align: justify;\">Gokulshree School Of Management And Technology Lvt Ltd</span></span></p>\r\n<p style=\"text-align: justify;\"><strong><span style=\"color: rgb(0, 0, 255);\"><span style=\"background-color: rgb(255, 255, 255);\"><span style=\"font-family: Cabin, sans-serif; font-size: 16px; text-align: start;\">Head Office-&nbsp;</span></span></span><span style=\"color: rgb(0, 0, 255);\"><span style=\"font-family: Cabin, sans-serif; font-size: 16px;\">Gilaula Road Laxman Nagar Shrawasti -Uttar Pradesh -271804</span></span></strong></p>\r\n<p style=\"text-align: justify;\">In most instances, our marketing emails sent to you will also contain a link to unsubscribe so that you will not receive further marketing communication from us.</p>\r\n<p style=\"text-align: justify;\"><strong>3. Disclosure - for legal reasons</strong></p>\r\n<p style=\"text-align: justify;\">We will share personal information with companies, organizations or individuals outside of GSMT Institute if it is necessary to:</p>\r\n<p style=\"text-align: justify;\">meet any applicable law, regulation, legal process or enforceable governmental request.</p>\r\n<p style=\"text-align: justify;\">enforce applicable Terms of Service, including investigation of potential violations.</p>\r\n<p style=\"text-align: justify;\">detect, prevent, or otherwise address fraud, security or technical issues.</p>\r\n<p style=\"text-align: justify;\">4. Payment Gateway</p>\r\n<p style=\"text-align: justify;\">All financial and billing information that we collect through the Site is used solely to check the qualifications of prospective customers and to bill for the Service. M.S. Baijnath Institute&nbsp;uses third-party intermediary(ies) to manage the credit card processing. This(ese) intermediary(ies) uses the information for the sole purpose of credit card processing. This billing information is not used by GSMT Institute&nbsp;for marketing or promotional purposes.</p>\r\n<p style=\"text-align: justify;\">We or the third party intermediary(ies) do not store your card data on their servers. The data is encrypted through the Payment Card Industry Data Security Standard (PCI-DSS) when processing payment. Your purchase transaction data is only used as long as is necessary to complete your purchase transaction. After that is complete, your purchase transaction information is not saved.</p>\r\n<p style=\"text-align: justify;\">Our payment gateway adheres to the standards set by PCI-DSS as managed by the PCI Security Standards Council, which is a joint effort of brands like Visa, MasterCard, American Express and Discover. PCI-DSS requirements help ensure the secure handling of credit card information by our store and its service providers.</p>\r\n<p style=\"text-align: justify;\"><strong>5. Disclosure - 3rd party for fulfilment of service</strong></p>\r\n<p style=\"text-align: justify;\">The third-party providers used by us will only collect, use and disclose your information to the extent necessary to allow them to perform the services they provide to us.</p>\r\n<p style=\"text-align: justify;\">However, certain third-party service providers, such as payment gateways and other payment transaction processors, have their own privacy policies in respect to the information we are required to provide to them for your purchase-related transactions.</p>\r\n<p style=\"text-align: justify;\">For these providers, we recommend that you read their privacy policies so you can understand the manner in which your personal information will be handled by these providers.</p>\r\n<p style=\"text-align: justify;\">In particular, remember that certain providers may be located in or have facilities that are located in a different jurisdiction than either you or us. So if you elect to proceed with a transaction that involves the services of a third-party service provider, then your information may become subject to the laws of the jurisdiction(s) in which that service provider or its facilities are located.</p>\r\n<p style=\"text-align: justify;\">Once you leave our website or are redirected to a third-party website or application, you are no longer governed by this Privacy Policy or our websites Terms of Service.</p>\r\n<p style=\"text-align: justify;\"><strong>6. Links</strong></p>\r\n<p style=\"text-align: justify;\">When you click on links on our website, they may direct you away from our site. We are not responsible for the privacy practices of other sites and encourage you to read their privacy statements.</p>\r\n<p style=\"text-align: justify;\"></p>\r\n<p style=\"text-align: justify;\"><strong>7. Security and Retention of data</strong></p>\r\n<p style=\"text-align: justify;\">To protect your personal information, we take reasonable precautions and follow industry best practices to make sure it is not inappropriately lost, misused, accessed, disclosed, altered or destroyed.</p>\r\n<p style=\"text-align: justify;\">GSMT Institute will keep personal information of its users for as long as they are registered subscribers or users of our products and services, and for a reasonable time thereafter.</p>\r\n<p style=\"text-align: justify;\"><strong>Cookies and opting out</strong></p>\r\n<p style=\"text-align: justify;\">We use cookies to maintain session of our users. It is not used to personally identify you on other websites.</p>\r\n<p style=\"text-align: justify;\"><strong>Google Anayltics and information collected</strong></p>\r\n<p style=\"text-align: justify;\">Google Analytics is a web analysis service provided by Google. Google utilizes the data collected to track and examine the use of kitedu.in and all subdomains of kitedu.in, to prepare reports on the activities of the websites and share them with other Google services.</p>\r\n<p style=\"text-align: justify;\">Google may use the data collected to contextualize and personalize the ads of its own advertising network.</p>\r\n<p style=\"text-align: justify;\">For more detailed information about personal data collected, cookie and usage data collected by Google and the place of processing such information, refer to Googles privacy policy here.</p>\r\n<p style=\"text-align: justify;\"><strong>Facebook Remarketing</strong></p>\r\n<p style=\"text-align: justify;\">Facebook Custom Audience is a Remarketing and Behavioral Targeting service provided by Facebook, Inc. that connects the activity of this Application with the Facebook advertising network.</p>\r\n<p style=\"text-align: justify;\">Personal Data collected: Cookies and email address. For more detailed information about personal data collected, cookie and usage data collected by Facebook and the place of processing such information, refer to Facebooks privacy policy here.</p>\r\n<p style=\"text-align: justify;\"><strong>8. Age of consent</strong></p>\r\n<p style=\"text-align: justify;\">By using this site, you represent that you are at least the age of majority in your state or province of residence, or that you are the age of majority in your state or province of residence and you have given us your consent to allow any of your minor dependents to use this site.</p>\r\n<p style=\"text-align: justify;\"><strong>9. Changes to this privacy policy</strong></p>\r\n<p style=\"text-align: justify;\">We reserve the right to modify this privacy policy at any time, so please review it frequently. Changes and clarifications will take effect immediately upon their posting on the website. If we make material changes to this policy, we will notify you here that it has been updated, so that you are aware of what information we collect, how we use it, and under what circumstances, if any, we use and/or disclose it.</p>\r\n<p style=\"text-align: justify;\">If our website is acquired or merged with another company, your information may be transferred to the new owners so that we may continue to offer services to you.</p>\r\n<p style=\"text-align: justify;\"><strong>10. Questions and contact information</strong></p>\r\n<p style=\"text-align: justify;\">If you would like to: access, correct, amend or delete any personal information we have about you, register a complaint, or simply want more information contact us at gokulshreeschool@gmail.com or by mail at</p>\r\n<p style=\"text-align: justify;\"><span style=\"color: rgb(255, 0, 0); font-family: Tahoma; font-size: 18.6667px; font-weight: 700;\">Gokulshree School Of Management And Technology Lvt Ltd</span><strong><span style=\"color: rgb(0, 0, 255);\"><span style=\"background-color: rgb(255, 255, 255);\"><br style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; color: rgb(204, 204, 204); font-family: Cabin, sans-serif; font-size: 16px; text-align: start; background-color: rgb(22, 21, 77);\" />\r\n</span></span></strong><strong><span style=\"color: rgb(0, 0, 255);\"><span style=\"font-family: Cabin, sans-serif; font-size: 16px; text-align: start;\">Head Office-&nbsp;</span></span><span style=\"color: rgb(0, 0, 255);\"><span style=\"font-family: Cabin, sans-serif; font-size: 16px;\">Gilaula Road Laxman Nagar Shrawasti -Uttar Pradesh -271804</span></span></strong></p>'),
(27, 16, 'Abhishek Kumar, CCC/Tally (Grade-C/A+)', 5, '', '1727977834672.jpg', 0, 1, '<p><span style=\"color: rgb(255, 255, 255);\"><strong>&nbsp;</strong></span><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-weight: 700; color: rgb(119, 119, 119); font-family: Cabin, sans-serif; font-size: 16px; text-align: justify;\">It was a great experience studying at GSMT Institute, a memory to cherish for lifetime. If you want to make a career in Graphic Designing, E- Accounting &amp; CCC Computer Courses. I would highly recommend you to join&nbsp;<font color=\"#ff0000\" style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none;\">Gokulshree School Of Management And Technology Pvt Ltd</font>.&rdquo;</span><span style=\"color: rgb(255, 255, 255);\"><strong><span style=\"font-size: medium;\"><span style=\"font-family: &quot;Times New Roman&quot;;\">&nbsp;experience at RGP Institute is great and memorable. The mentors at RGPI helped us enhance my academic and interpersonal skills. I am thankful to Training&nbsp; for providing a platform to enhance my skills and an opportunity to showcase them&quot;.</span></span></strong></span><strong><span style=\"font-size: medium;\"><span style=\"font-family: &quot;Times New Roman&quot;;\"><span style=\"color: rgba(0, 0, 0, 0.5);\">&nbsp;</span></span></span></strong></p>\r\n<p><strong> </strong></p>\r\n<p></p>\r\n<p></p>\r\n<p></p>');
INSERT INTO `page` (`id`, `parent_id`, `name`, `weight`, `pile_height`, `imname`, `show_on`, `status`, `descr`) VALUES
(32, 0, 'Franchise Process', 8, '', '', 0, 0, '<p class=\"MsoNormal\" style=\"margin-top:6.8pt;margin-right:0in;margin-bottom:6.8pt;&#10;margin-left:0in;line-height:normal;mso-outline-level:4;vertical-align:baseline\"><b><span style=\"font-size:12.0pt;font-family:&#10;&quot;Times New Roman&quot;,&quot;serif&quot;;mso-fareast-font-family:&quot;Times New Roman&quot;;color:#E36C0A;&#10;mso-themecolor:accent6;mso-themeshade:191\">HOW TO TAKE MEMBERSHIP :<o:p></o:p></span></b></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom:2.7pt;line-height:14.25pt;vertical-align:&#10;baseline\"><b><span style=\"font-size:12.0pt;&#10;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;mso-fareast-font-family:&quot;Times New Roman&quot;\">On receiving this offer, a prospective study centre should.<o:p></o:p></span></b></p>\r\n<p class=\"MsoNormal\" style=\"margin-top:0in;margin-right:0in;margin-bottom:0in;&#10;margin-left:-10.2pt;margin-bottom:.0001pt;text-indent:-.25in;line-height:20.4pt;&#10;mso-list:l2 level1 lfo1;tab-stops:list .5in;vertical-align:baseline\"><!--[if !supportLists]--><span style=\"font-size:10.0pt;mso-bidi-font-size:12.0pt;font-family:Symbol;&#10;mso-fareast-font-family:Symbol;mso-bidi-font-family:Symbol\">&middot;<span style=\"font-variant-numeric: normal; font-variant-east-asian: normal; font-stretch: normal; font-size: 7pt; line-height: normal; font-family: &quot;Times New Roman&quot;;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </span></span><!--[endif]--><span style=\"font-size:12.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;mso-fareast-font-family:&quot;Times New Roman&quot;\">Apply with complete details of self, premises, available hardware, plan for business development in the format of the data sheet attached at the end of this offer.<o:p></o:p></span></p>\r\n<p class=\"MsoNormal\" style=\"margin-top:0in;margin-right:0in;margin-bottom:0in;&#10;margin-left:-10.2pt;margin-bottom:.0001pt;text-indent:-.25in;line-height:20.4pt;&#10;mso-list:l2 level1 lfo1;tab-stops:list .5in;vertical-align:baseline\"><!--[if !supportLists]--><span style=\"font-size:10.0pt;mso-bidi-font-size:12.0pt;font-family:Symbol;&#10;mso-fareast-font-family:Symbol;mso-bidi-font-family:Symbol\">&middot;<span style=\"font-variant-numeric: normal; font-variant-east-asian: normal; font-stretch: normal; font-size: 7pt; line-height: normal; font-family: &quot;Times New Roman&quot;;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </span></span><!--[endif]--><span style=\"font-size:12.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;mso-fareast-font-family:&quot;Times New Roman&quot;\">Receipt of the application and data sheet at the controlling office of&nbsp;&nbsp;</span><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-weight: 700; color: rgb(119, 119, 119); font-family: Tahoma; font-size: 18.6667px; text-align: justify; text-indent: 0px;\">GSMT</span><span style=\"font-size:12.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;mso-fareast-font-family:&quot;Times New Roman&quot;\">&nbsp; would be followed by personal interview with the Director&nbsp;</span><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-weight: 700; color: rgb(119, 119, 119); font-family: Tahoma; font-size: 18.6667px; text-align: justify; text-indent: 0px;\">GSMT</span><span style=\"font-size:12.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;mso-fareast-font-family:&quot;Times New Roman&quot;\">&nbsp;&nbsp;and a visit by a team of&nbsp;</span><span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: none; outline: none; font-weight: 700; color: rgb(119, 119, 119); font-family: Tahoma; font-size: 18.6667px; text-align: justify; text-indent: 0px;\">GSMT</span><span style=\"font-size:12.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;mso-fareast-font-family:&quot;Times 