(36, 34, 'Examination Process', 2, '', '', 0, 1, '<p>Online Exam By Gokulshree School Of Management And Technology Pvt Ltd&nbsp;</p>\r\n<p>Visit :- www.gokulshreeschool.ocm</p>'),
(37, 34, 'Placement', 3, '', '', 0, 1, '<p><span style=\"font-size: large;\"><span style=\"color: rgb(0, 0, 255);\"><b>DL DIGITAL&nbsp;</b></span></span></p>\r\n<p><b>Agency, Shop, Flipkart, Amazon&nbsp;</b></p>'),
(38, 32, 'Why GSMT?', 1, '', '', 0, 1, '<h2 style=\"box-sizing: border-box; margin: 0px; padding: 0px 0px 28px; border: none; outline: none; font-family: &quot;Hind Madurai&quot;, sans-serif; line-height: 1.6em; color: rgb(68, 68, 68); font-size: 30px; position: relative; background-image: none; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; text-transform: uppercase;\"><span style=\"font-size: medium;\">GOKULSHREE SCHOOL OF MANAGEMENT AND TECHNOLOGY PVT LTD</span></h2>\r\n<p class=\"MsoNormal\" style=\"margin-bottom:6.8pt;text-align:justify;line-height:&#10;normal\"><strong><font face=\"Times New Roman, serif\"><span style=\"font-size: 16px;\">GSMT is&nbsp; An Autonomous Body Registered under SR Act, 9(1)2012</span></font></strong><font face=\"Times New Roman, serif\"><span style=\"font-size: 16px;\">&nbsp;</span></font><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&#10;&quot;Times New Roman&quot;,&quot;serif&quot;;mso-fareast-font-family:&quot;Times New Roman&quot;\">&nbsp;is a national program meant to impart information technology education to people countrywide. Ours is an ISO certified firm and can be useful for computer institute govt. registration/ computer institute registration/ computer center registration. Besides, we undertake requirements related to new computer institute registration. We are supported by a team of diligent individuals, who assist our clients in the complete computer institute registration process. So, contact us anytime.<o:p></o:p></span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom:6.8pt;text-align:justify;line-height:&#10;normal\"><strong><font face=\"Times New Roman, serif\"><span style=\"font-size: 16px;\">GSMT&nbsp;</span></font></strong><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&#10;&quot;Times New Roman&quot;,&quot;serif&quot;;mso-fareast-font-family:&quot;Times New Roman&quot;\">&nbsp;provides single source for quality assurance in computer education among the nations non-formal institutes, After turning out competent IT professionals in large numbers. <strong>GSMT</strong> aims to provides maximum benefits to ALC&nbsp; and Students with quality...<o:p></o:p></span></p>\r\n<p class=\"MsoNormal\" style=\"margin-top:6.8pt;margin-right:0in;margin-bottom:13.6pt;&#10;margin-left:0in;line-height:normal;mso-outline-level:1\"><b><span style=\"font-size:16.5pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;mso-fareast-font-family:&#10;&quot;Times New Roman&quot;;color:#E36C0A;mso-themecolor:accent6;mso-themeshade:191;&#10;mso-font-kerning:18.0pt\">Institute Registration<o:p></o:p></span></b></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom:6.8pt;line-height:normal\"><b><span style=\"font-size:12.0pt;mso-bidi-font-size:11.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;mso-fareast-font-family:&quot;Times New Roman&quot;\">Benefits of Affiliation: -</span></b><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;mso-fareast-font-family:&quot;Times New Roman&quot;\"><o:p></o:p></span></p>\r\n<ul type=\"disc\">\r\n    <li class=\"MsoNormal\" style=\"mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;&#10;     line-height:normal;mso-list:l1 level1 lfo1;tab-stops:list .5in\"><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;     mso-fareast-font-family:&quot;Times New Roman&quot;\">An ISO Certified Organization.<o:p></o:p></span></li>\r\n    <li class=\"MsoNormal\" style=\"mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;&#10;     line-height:normal;mso-list:l1 level1 lfo1;tab-stops:list .5in\"><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;     mso-fareast-font-family:&quot;Times New Roman&quot;\">A Globally Famous Organization.<o:p></o:p></span></li>\r\n    <li class=\"MsoNormal\" style=\"mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;&#10;     line-height:normal;mso-list:l1 level1 lfo1;tab-stops:list .5in\"><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;     mso-fareast-font-family:&quot;Times New Roman&quot;\">All India Valid Certificate.<o:p></o:p></span></li>\r\n    <li class=\"MsoNormal\" style=\"mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;&#10;     line-height:normal;mso-list:l1 level1 lfo1;tab-stops:list .5in\"><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;     mso-fareast-font-family:&quot;Times New Roman&quot;\">Lowest course fees.<o:p></o:p></span></li>\r\n    <li class=\"MsoNormal\" style=\"mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;&#10;     line-height:normal;mso-list:l1 level1 lfo1;tab-stops:list .5in\"><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;     mso-fareast-font-family:&quot;Times New Roman&quot;\">Brand Promotion /Advertisements      Support<o:p></o:p></span></li>\r\n    <li class=\"MsoNormal\" style=\"mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;&#10;     line-height:normal;mso-list:l1 level1 lfo1;tab-stops:list .5in\"><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;     mso-fareast-font-family:&quot;Times New Roman&quot;\">Since we are examination body      we do not share from course fees given in Prospectus. Only Registration &nbsp;fees will be charged by the ALC.<o:p></o:p></span></li>\r\n    <li class=\"MsoNormal\" style=\"mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;&#10;     line-height:normal;mso-list:l1 level1 lfo1;tab-stops:list .5in\"><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;     mso-fareast-font-family:&quot;Times New Roman&quot;\">Online&nbsp; mode of      exam.<o:p></o:p></span></li>\r\n    <li class=\"MsoNormal\" style=\"mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;&#10;     line-height:normal;mso-list:l1 level1 lfo1;tab-stops:list .5in\"><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;     mso-fareast-font-family:&quot;Times New Roman&quot;\">High-standard and navigation      friendly course materials, question papers, innovative and industry      friendly course structure.<o:p></o:p></span></li>\r\n    <li class=\"MsoNormal\" style=\"mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;&#10;     line-height:normal;mso-list:l1 level1 lfo1;tab-stops:list .5in\"><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;     mso-fareast-font-family:&quot;Times New Roman&quot;\">Training Support for your      Faculty, counselor and marketing team.<o:p></o:p></span></li>\r\n    <li class=\"MsoNormal\" style=\"mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;&#10;     line-height:normal;mso-list:l1 level1 lfo1;tab-stops:list .5in\"><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;     mso-fareast-font-family:&quot;Times New Roman&quot;\">Marketing inputs &amp;      guidelines for a sustainable business.<o:p></o:p></span></li>\r\n    <li class=\"MsoNormal\" style=\"mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;&#10;     line-height:normal;mso-list:l1 level1 lfo1;tab-stops:list .5in\"><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;     mso-fareast-font-family:&quot;Times New Roman&quot;\">Automated tools for tracking      your business in a single portal that will help you analyse, monitor and      manage your growth.<o:p></o:p></span></li>\r\n    <li class=\"MsoNormal\" style=\"mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;&#10;     line-height:normal;mso-list:l1 level1 lfo1;tab-stops:list .5in\"><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;     mso-fareast-font-family:&quot;Times New Roman&quot;\">A transparent and user friendly      single window online portal for all transactions and operational inputs.<o:p></o:p></span></li>\r\n    <li class=\"MsoNormal\" style=\"mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;&#10;     line-height:normal;mso-list:l1 level1 lfo1;tab-stops:list .5in\"><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;     mso-fareast-font-family:&quot;Times New Roman&quot;\">High quality standard designs      of promotional materials for local promotion.<o:p></o:p></span></li>\r\n    <li class=\"MsoNormal\" style=\"mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;&#10;     line-height:normal;mso-list:l1 level1 lfo1;tab-stops:list .5in\"><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;     mso-fareast-font-family:&quot;Times New Roman&quot;\">Placement assistance.<o:p></o:p></span></li>\r\n</ul>\r\n<p class=\"MsoNormal\" style=\"margin-top:6.8pt;margin-right:0in;margin-bottom:13.6pt;&#10;margin-left:0in;line-height:normal;mso-outline-level:1\"><b><span style=\"font-size:16.5pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;mso-fareast-font-family:&#10;&quot;Times New Roman&quot;;color:#E36C0A;mso-themecolor:accent6;mso-themeshade:191;&#10;mso-font-kerning:18.0pt\">Student Registration<o:p></o:p></span></b></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom:6.8pt;line-height:normal\"><b><span style=\"font-size:12.0pt;mso-bidi-font-size:11.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;mso-fareast-font-family:&quot;Times New Roman&quot;\">Benefits of Registration: -</span></b><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;mso-fareast-font-family:&quot;Times New Roman&quot;\"><o:p></o:p></span></p>\r\n<ul type=\"disc\">\r\n    <li class=\"MsoNormal\" style=\"mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;&#10;     line-height:normal;mso-list:l0 level1 lfo2;tab-stops:list .5in\"><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;     mso-fareast-font-family:&quot;Times New Roman&quot;\">Online exam at your      ALC.<o:p></o:p></span></li>\r\n    <li class=\"MsoNormal\" style=\"mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;&#10;     line-height:normal;mso-list:l0 level1 lfo2;tab-stops:list .5in\"><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;     mso-fareast-font-family:&quot;Times New Roman&quot;\">Free Live Project Training for      Scholars.<o:p></o:p></span></li>\r\n    <li class=\"MsoNormal\" style=\"mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;&#10;     line-height:normal;mso-list:l0 level1 lfo2;tab-stops:list .5in\"><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;     mso-fareast-font-family:&quot;Times New Roman&quot;\">Quality education provided at      very affordable charge.<o:p></o:p></span></li>\r\n    <li class=\"MsoNormal\" style=\"mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;&#10;     line-height:normal;mso-list:l0 level1 lfo2;tab-stops:list .5in\"><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;     mso-fareast-font-family:&quot;Times New Roman&quot;\">Globally accepted Certificate      after the completion of course.<o:p></o:p></span></li>\r\n    <li class=\"MsoNormal\" style=\"mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;&#10;     line-height:normal;mso-list:l0 level1 lfo2;tab-stops:list .5in\"><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;     mso-fareast-font-family:&quot;Times New Roman&quot;\">Value added on services like      personality developments, Multilanguage learning.<o:p></o:p></span></li>\r\n    <li class=\"MsoNormal\" style=\"mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;&#10;     line-height:normal;mso-list:l0 level1 lfo2;tab-stops:list .5in\"><span style=\"font-size:12.0pt;mso-bidi-font-size:9.0pt;font-family:&quot;Times New Roman&quot;,&quot;serif&quot;;&#10;     mso-fareast-font-family:&quot;Times New Roman&quot;\">Free placement assistance.<o:p></o:p></span></li>\r\n</ul>\r\n<p><span style=\"font-family: &quot;Times New Roman&quot;, serif;\">&nbsp;</span>&nbsp;</p>'),
