(27, 41, '3', 2, '1', '<p>&nbsp;</p>\r\n<div style=\"mso-element:frame;mso-element-frame-hspace:9.0pt;mso-element-wrap:&#10;around;mso-element-anchor-vertical:paragraph;mso-element-anchor-horizontal:&#10;margin;mso-element-top:8.6pt;mso-height-rule:exactly\">\r\n<table cellspacing=\"0\" cellpadding=\"0\" hspace=\"0\" vspace=\"0\" align=\"left\">\r\n    <tbody>\r\n        <tr>\r\n            <td valign=\"top\" align=\"left\" style=\"padding-top:0in;padding-right:9.0pt;&#10;  padding-bottom:0in;padding-left:9.0pt\">\r\n            <p class=\"MsoNormal\" style=\"mso-element:frame;mso-element-frame-hspace:9.0pt;&#10;  mso-element-wrap:around;mso-element-anchor-vertical:paragraph;mso-element-anchor-horizontal:&#10;  margin;mso-element-top:8.6pt;mso-height-rule:exactly\"><span lang=\"EN-IN\" style=\"font-size:12.0pt;line-height:107%;font-family:&quot;Verdana&quot;,&quot;sans-serif&quot;;&#10;  mso-fareast-font-family:&quot;Times New Roman&quot;;mso-bidi-font-family:&quot;Times New Roman&quot;;&#10;  mso-fareast-language:EN-IN;mso-bidi-language:HI\">1. Data or information used   to run the computer is called:<span style=\"mso-spacerun:yes\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></span></p>\r\n            <p class=\"MsoNormal\" style=\"mso-element:frame;mso-element-frame-hspace:9.0pt;&#10;  mso-element-wrap:around;mso-element-anchor-vertical:paragraph;mso-element-anchor-horizontal:&#10;  margin;mso-element-top:8.6pt;mso-height-rule:exactly\"></p>\r\n            </td>\r\n        </tr>\r\n    </tbody>\r\n</table>\r\n</div>', '<p>&nbsp;<span style=\"font-family: Verdana, sans-serif; font-size: 16px;\">(A) Software</span><span style=\"font-family: Verdana, sans-serif; font-size: 16px;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span><span style=\"font-family: Verdana, sans-serif; font-size: 16px;\">&nbsp;&nbsp;&nbsp;</span></p>', '<p>&nbsp;<span style=\"font-family: Verdana, sans-serif; font-size: 16px;\">(B) Hardware</span><span style=\"font-family: Verdana, sans-serif; font-size: 16px;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></p>', '<p>&nbsp;<span style=\"font-family: Verdana, sans-serif; font-size: 16px;\">(C) Peripheral</span><span style=\"font-family: Verdana, sans-serif; font-size: 16px;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span><span style=\"font-family: Verdana, sans-serif; font-size: 16px;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></p>', '', '', '', '', '', '', '', '', '', '', 1, '<p>&nbsp;<span style=\"font-family: Verdana, sans-serif; font-size: 16px;\">(D)CPU</span></p>', 1, 'All', 0, 0, '', '', 0),
(28, 41, '3', 2, '1', '<p>&nbsp;</p>\r\n<div style=\"mso-element:frame;mso-element-frame-hspace:9.0pt;mso-element-wrap:&#10;around;mso-element-anchor-vertical:paragraph;mso-element-anchor-horizontal:&#10;margin;mso-element-top:8.6pt;mso-height-rule:exactly\">\r\n<table cellspacing=\"0\" cellpadding=\"0\" hspace=\"0\" vspace=\"0\" align=\"left\">\r\n    <tbody>\r\n        <tr>\r\n            <td valign=\"top\" align=\"left\" style=\"padding-top:0in;padding-right:9.0pt;&#10;  padding-bottom:0in;padding-left:9.0pt\">\r\n            <p class=\"MsoNormal\" style=\"mso-element:frame;mso-element-frame-hspace:9.0pt;&#10;  mso-element-wrap:around;mso-element-anchor-vertical:paragraph;mso-element-anchor-horizontal:&#10;  margin;mso-element-top:8.6pt;mso-height-rule:exactly\"><span lang=\"EN-IN\" style=\"font-size:12.0pt;line-height:107%;font-family:&quot;Verdana&quot;,&quot;sans-serif&quot;;&#10;  mso-fareast-font-family:&quot;Times New Roman&quot;;mso-bidi-font-family:&quot;Times New Roman&quot;;&#10;  mso-fareast-language:EN-IN;mso-bidi-language:HI\">One MB is equal to?<span style=\"mso-tab-count:1\">&nbsp; </span></span><span style=\"font-size:12.0pt;&#10;  line-height:107%;font-family:&quot;Verdana&quot;,&quot;sans-serif&quot;;mso-fareast-font-family:&#10;  &quot;Times New Roman&quot;;mso-bidi-font-family:&quot;Times New Roman&quot;;mso-ansi-language:&#10;  EN-US\"><o:p></o:p></span></p>\r\n            <p class=\"MsoNormal\" style=\"mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;&#10;  line-height:normal;mso-element:frame;mso-element-frame-hspace:9.0pt;&#10;  mso-element-wrap:around;mso-element-anchor-vertical:paragraph;mso-element-anchor-horizontal:&#10;  margin;mso-element-top:8.6pt;mso-height-rule:exactly\"></p>\r\n            </td>\r\n        </tr>\r\n    </tbody>\r\n</table>\r\n</div>', '<p>&nbsp;<span style=\"font-family: Verdana, sans-serif; font-size: 16px;\">&nbsp;</span><span style=\"font-family: Verdana, sans-serif; font-size: 16px;\">(A) 500 GB</span><span