(29, 41, '3', 2, '1', '<p>&nbsp;&nbsp;</p>\r\n<div>\r\n<table cellspacing=\"0\" cellpadding=\"0\" hspace=\"0\" vspace=\"0\" align=\"left\">\r\n    <tbody>\r\n        <tr>\r\n            <td valign=\"top\" align=\"left\" style=\"padding: 0in 9pt;\">\r\n            <p class=\"MsoNormal\"><span lang=\"EN-IN\" style=\"font-size: 12pt; line-height: 17.12px; font-family: Verdana, sans-serif;\">Data or information used to run the computer is called:&nbsp; &nbsp; &nbsp;</span></p>\r\n            </td>\r\n        </tr>\r\n    </tbody>\r\n</table>\r\n</div>', '<p>&nbsp;<span style=\"font-family: Verdana, sans-serif; font-size: 16px;\">(A) Software</span><span style=\"font-family: Verdana, sans-serif; font-size: 16px;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span><span style=\"font-family: Verdana, sans-serif; font-size: 16px;\">&nbsp;</span></p>', '<p>&nbsp;<span style=\"font-family: Verdana, sans-serif; font-size: 16px;\">&nbsp;&nbsp;</span><span style=\"font-family: Verdana, sans-serif; font-size: 16px;\">(B) Hardware</span><span style=\"font-family: Verdana, sans-serif; font-size: 16px;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></p>', '<p>&nbsp;<span style=\"font-family: Verdana, sans-serif; font-size: 16px;\">(C) Peripheral</span><span style=\"font-family: Verdana, sans-serif; font-size: 16px;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span><span style=\"font-family: Verdana, sans-serif; font-size: 16px;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></p>', '<p>&nbsp;<span style=\"font-family: Verdana, sans-serif; font-size: 16px;\">(D)CPU</span></p>', '', '', '', '', '', '', '', '', '', 1, '', 1, 'All', 0, 0, '<div style=\"mso-element:frame;mso-element-frame-hspace:9.0pt;mso-element-wrap:&#10;around;mso-element-anchor-vertical:paragraph;mso-element-anchor-horizontal:&#10;margin;mso-element-top:8.6pt;mso-height-rule:exactly\">\r\n<table cellspacing=\"0\" cellpadding=\"0\" hspace=\"0\" vspace=\"0\" align=\"left\">\r\n    <tbody>\r\n        