(648, 79, '1', 50, '1', '<p>&nbsp;<span style=\"color: rgba(41, 41, 41, 0.9); font-family: Poppins, sans-serif; font-size: 18px;\">Progress of expenses against budget allocation may be compared to the trial balance of original company using _________menu in Trial Balance.</span></p>\r\n<p style=\"box-sizing: inherit; margin: 0px 0px 1.333em; word-break: break-word; color: rgba(41, 41, 41, 0.9); font-family: Poppins, sans-serif; font-size: 18px;\"><span lang=\"HI\" style=\"box-sizing: inherit; font-family: &quot;Arial Unicode MS&quot;, &quot;sans-serif&quot;; line-height: 20.7px;\">à¤¬à¤à¤ à¤à¤µà¤à¤à¤¨ à¤à¥ à¤µà¤¿à¤°à¥à¤¦à¥à¤§ à¤µà¥à¤¯à¤¯ à¤à¥ à¤ªà¥à¤°à¤à¤¤à¤¿ à¤à¥ à¤¤à¥à¤²à¤¨à¤¾ à¤à¥à¤°à¤¾à¤¯à¤² à¤¬à¥à¤²à¥à¤à¤¸ à¤®à¥à¤&nbsp;</span>_________<span lang=\"HI\" style=\"box-sizing: inherit; font-family: &quot;Arial Unicode MS&quot;, &quot;sans-serif&quot;; line-height: 20.7px;\">à¤®à¥à¤¨à¥ à¤à¤¾ à¤à¤ªà¤¯à¥à¤ à¤à¤°à¤à¥ à¤®à¥à¤² à¤à¤à¤ªà¤¨à¥ à¤à¥ à¤à¥à¤°à¤¾à¤¯à¤² à¤¬à¥à¤²à¥à¤à¤¸ à¤¸à¥ à¤à¥ à¤à¤¾ à¤¸à¤à¤¤à¥ à¤¹à¥à¥¤</span></p>', '<p>&nbsp;<span style=\"font-family: Poppins, sans-serif; font-size: 18px;\">Budget (Alt +B)</span></p>', '<p>&nbsp;<span style=\"font-family: Poppins, sans-serif; font-size: 18px;\">Column (Alt +C)</span></p>', '<p>&nbsp;<span style=\"font-family: Poppins, sans-serif; font-size: 18px;\">Alt +F6</span></p>', '<p>&nbsp;<span style=\"font-family: Poppins, sans-serif; font-size: 18px;\">Ctrl+F7</span></p>', '', '', '', '', '', '', '', '', '', 1, '', 1, '149', 149, 0, '', '1', 0),
