(695, 79, '1', 50, '1', '<p>&nbsp;<span style=\"color: rgba(41, 41, 41, 0.9); font-family: Poppins, sans-serif; font-size: 18px;\">&nbsp;</span><span style=\"color: rgba(41, 41, 41, 0.9); font-family: Poppins, sans-serif; font-size: 18px;\">How many inbuilt Accounts group are in tally by default?</span></p>\r\n<p style=\"box-sizing: inherit; margin: 0px 0px 1.333em; word-break: break-word; color: rgba(41, 41, 41, 0.9); font-family: Poppins, sans-serif; font-size: 18px;\"><span lang=\"HI\" style=\"box-sizing: inherit; font-family: &quot;Arial Unicode MS&quot;, &quot;sans-serif&quot;; line-height: 20.7px;\">à¤¡à¤¿à¤«à¤¼à¥à¤²à¥à¤ à¤°à¥à¤ª à¤¸à¥ à¤à¤¿à¤¤à¤¨à¥ à¤à¤¨à¤¬à¤¿à¤²à¥à¤ à¤INSERT INTO `product` (`id`, `parent_id`, `program`, `cat_id`, `price`, `question`, `option1`, `option2`, `option3`, `option4`, `option5`, `hquestion`, `hpassage`, `hoption1`, `hoption2`, `hoption3`, `hoption4`, `hoption5`, `hdescr`, `answer`, `descr`, `status`, `sid`, `sub`, `level`, `passage`, `ccode`, `sstatus`) VALUES
(730, 80, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Which one of the following is not used in media access control?</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">ethernet</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">digital subscriber line</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">fiber distributed data interface</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;packet switching</span></p>', '', '', '', '', '', '', '', '', '', 4, '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Answer: d</span><br style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\" />\r\n<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Explanation: Packet switching is not really related to media access control as it just features delivery of packets of data between devices over a shared network. Internet is actually based on packet switching.</span></p>', 1, '92', 92, 0, '', '1', 0),
(731, 80, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">The IETF standards documents are called ________</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">RFC</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">RCF</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">ID</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">DFC</span></p>', '', '', '', '', '', '', '', '', '', 1, '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Answer: a</span><br style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\" />\r\n<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Explanation: RFC stands for Request For Comments and they are documents that describe methods, behaviors, research, or innovations applicable to the working of the Internet.</span></p>', 1, '92', 92, 0, '', '1', 0),
(732, 80, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">In the layer hierarchy as the data packet moves from the upper to the lower layers, headers are ___________</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Added</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;Removed</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Rearranged</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Modified</span></p>', '<div></div>\r\n<div class=\"sf-desktop-ads\" style=\"border: 0px; margin: 0px; padding: 0px; color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\"></div>', '', '', '', '', '', '', '', '', 1, '<p>&nbsp;&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Answer: a</span></p>\r\n<div id=\"target-id6863f91edeabb\" class=\"collapseomatic_content \" style=\"border: 0px; margin: 0px 0px 30px 16px; padding: 0px; color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Explanation: Each layer adds its own header to the packet from the previous layer. For example, in the Internet layer, the IP header is added over the TCP header on the data packet that came from the transport layer.</div>\r\n<div></div>', 1, '92', 92, 0, '', '1', 0),
(733, 80, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;The structure or format of data is called ___________</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;Syntax</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Semantics</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Struct</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Formatting</span></p>', '', '', '', '', '', '', '', '', '', 1, '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Answer: a</span><br style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\" />\r\n<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Explanation: The structure and format of data are defined using syntax. Semantics defines how a particular pattern to be interpreted, and what action is to be taken based on that interpretation. In programming languages, syntax of the instructions plays a vital role in designing of the program.</span></p>', 1, '92', 92, 0, '', '1', 0),
(734, 80, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Communication between a computer and a keyboard involves ______________ transmission.</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Automatic</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Half-duplex</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;Full-duplex</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;Simplex</span></p>', '', '', '', '', '', '', '', '', '', 4, '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Answer: d</span></p>\r\n<div id=\"target-id6863f91edead4\" class=\"collapseomatic_content \" style=\"border: 0px; margin: 0px 0px 30px 16px; padding: 0px; color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Explanation: In simplex transmission, data flows in single direction which in this case refers to the data flowing from the keyboard to the computer. Another example would be of the mouse where the data flows from the mouse to the computer only.</div>\r\n<div></div>', 1, '92', 92, 0, '', '1', 0),
(735, 80, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">The first Network was called ________</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;CNNET</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">NSFNET</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">ASAPNET</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;ARPANET</span></p>', '', '', '', '', '', '', '', '', '', 4, '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Answer: d</span><br style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\" />\r\n<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Explanation: ARPANET stands for Advanced Research Projects Agency Networks. It was the first network to be implemented which used the TCP/IP protocol in the year 1969.</span></p>', 1, '92', 92, 0, '', '1', 0),
(736, 80, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">A _______ is the physical path over which a message travels.</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Path</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Medium</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Protocol</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Route</span></p>', '', '', '', '', '', '', '', '', '', 2, '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Answer: b</span><br style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\" />\r\n<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Explanation: Messages travel from sender to receiver via a physical path called the medium using a set of methods/rules called protocol. Mediums can be guided (wired) or unguided (wireless).</span></p>', 1, '92', 92, 0, '', '1', 0),
(737, 80, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;Which organization has authority over interstate and international commerce in the communications field?</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;ITU-T</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;IEEE</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;FCC</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;ISOC</span></p>', '', '', '', '', '', '', '', '', '', 3, '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Answer: c</span><br style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\" />\r\n<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Explanation: FCC is the abbreviation for Federal Communications Commission. FCC is responsible for regulating all interstate communications originating or terminating in USA. It was founded in the year 1934.</span></p>', 1, '92', 92, 0, '', '1', 0),
(738, 80, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;Which of this is not a network edge device?</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">PC</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;Smartphones</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;Servers</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;Switch</span></p>', '', '', '', '', '', '', '', '', '', 4, '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Answer: d</span><br style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\" />\r\n<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Explanation: Network edge devices refer to host systems, which can host applications like web browser. A switch can&rsquo;t operate as a host, but as a central device which can be used to manage network communication.</span></p>', 1, '92', 92, 0, '', '1', 0),
(739, 80, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;A _________ set of rules that governs data communication.</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Protocols</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Standards</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">RFCs</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Servers</span></p>', '', '', '', '', '', '', '', '', '', 1, '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Answer: a</span><br style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\" />\r\n<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Explanation: In communications, a protocol refers to a set of rules and regulations that allow a network of nodes to transmit and receive information. Each layer in the network model has a protocol set, for example, the transport layer has TCP and UDP protocols.</span></p>', 1, '92', 92, 0, '', '1', 0),
(740, 80, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Three or more devices share a link in ________ connection.</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">&nbsp;Unipoint</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Multipoint</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Point to point</span></p>', '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Simplex</span></p>', '', '', '', '', '', '', '', '', '', 2, '<p>&nbsp;<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Answer: b</span><br style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\" />\r\n<span style=\"color: rgb(58, 58, 58); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 15px;\">Explanation: A multipoint communication is established when three or many network nodes are connected to each other. Frame relay, Ethernet and ATM are some examples of multipoint connections.</span></p>', 1, '92', 92, 0, '', '1', 0),
(741, 81, '1', 36, '1', '<p><span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 23px; letter-spacing: 1px;\">Party account can be created through</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Inventory creation window</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Group creation window</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Ledger creation window</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Any one of them</span></p>', '', '', '', '', '', '', '', '', '', 3, '', 1, '89', 89, 0, '', '1', 0),
(742, 81, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 23px; letter-spacing: 1px;\">For Export of Data from Company to Company Tally uses</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">XML Format</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">&nbsp;ASCII Format</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">SDF Format</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">None of these</span></p>', '', '', '', '', '', '', '', '', '', 1, '', 1, '89', 89, 0, '', '1', 0),
(743, 81, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 23px; letter-spacing: 1px;\">We can change the Company Information from</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Company Info &gt; View</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Company Info &gt; Split Company Data</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Company Info &gt; Back up</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Company Info &gt; Alter</span></p>', '', '', '', '', '', '', '', '', '', 4, '', 1, '89', 89, 0, '', '1', 0),
(744, 81, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 23px; letter-spacing: 1px;\">Manufacturing journal creates based on</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Purchase Quotation</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Stock Journal</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Receipt Note</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Journal</span></p>', '', '', '', '', '', '', '', '', '', 2, '', 1, '89', 89, 0, '', '1', 0),
(745, 81, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 23px; letter-spacing: 1px;\">Transfer from Main Cash to petty Cash you require to pass _____ voucher</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Contra</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Payment</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Receipt</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">None of these</span></p>', '', '', '', '', '', '', '', '', '', 1, '', 1, '89', 89, 0, '', '1', 0),
(746, 81, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 23px; letter-spacing: 1px;\">To show the cheque number while reconciling Bank Accounts press</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">CTRL + F11</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">CTRL + F12</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">&nbsp;F11</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">F12</span></p>', '', '', '', '', '', '', '', '', '', 4, '', 1, '89', 89, 0, '', '1', 0),
(747, 81, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 23px; letter-spacing: 1px;\">To activate Job Costing which options require to be activated?</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Maintain VAT</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Maintain Cost Centre</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Use Cost Centre for Job Costing</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Both b and c</span></p>', '', '', '', '', '', '', '', '', '', 4, '', 1, '89', 89, 0, '', '1', 0),
(748, 81, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 23px; letter-spacing: 1px;\">Service Tax Report can be seen from</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Display &gt; Account Books</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Display &gt; Statutory Reports</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Display &gt; Day Book</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Display &gt; Statutory Masters</span></p>', '', '', '', '', '', '', '', '', '', 2, '', 1, '89', 89, 0, '', '1', 0),
(749, 81, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 23px; letter-spacing: 1px;\">Retained Earnings is an alias of</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Investments</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Capital Account</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">Indirect Income</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">&nbsp;Reserve and surplus</span></p>', '', '', '', '', '', '', '', '', '', 4, '', 1, '89', 89, 0, '', '1', 0),
(750, 81, '1', 36, '1', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 23px; letter-spacing: 1px;\">Data Folder of a Company consists of</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">3 digits</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">4 digits</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">5 digits</span></p>', '<p>&nbsp;<span style=\"color: rgb(51, 51, 51); font-family: Roboto, sans-serif; font-size: 16px; letter-spacing: 1px;\">6 digits</span></p>', '', '', '', '', '', '', '', '', '', 3, '', 1, '89', 89, 0, '', '1', 0);
